To write unit tests for the `run_length_encode` function using pytest, we need to cover various scenarios including happy paths, edge cases, and error cases. Here's a set of tests that cover these scenarios:

```python
import pytest

def run_length_encode(s: str) -> list:
    if not s:
        return []
    result = []
    count = 1
    for i in range(1, len(s)):
        if s[i] == s[i-1]:
            count += 1
        else:
            result.append((s[i-1], count))
            count = 1
    result.append((s[-1], count))
    return result

# Happy path tests
def test_run_length_encode_empty_string():
    assert run_length_encode("") == []

def test_run_length_encode_single_character():
    assert run_length_encode("a") == [('a', 1)]

def test_run_length_encode_single_character_repeated():
    assert run_length_encode("aaa") == [('a', 3)]

def test_run_length_encode_multiple_characters():
    assert run_length_encode("aabbbcc") == [('a', 2), ('b', 3), ('c', 2)]

def test_run_length_encode_no_repetition():
    assert run_length_encode("abc") == [('a', 1), ('b', 1), ('c', 1)]

# Edge cases
def test_run_length_encode_empty_list():
    assert run_length_encode([]) == []

def test_run_length_encode_empty_list_as_string():
    assert run_length_encode("") == []

def test_run_length_encode_empty_string():
    assert run_length_encode("") == []

def test_run_length_encode_empty_string_with_spaces():
    assert run_length_encode("   ") == [(' ', 3)]

# Error cases
def test_run_length_encode_non_string_input():
    with pytest.raises(TypeError):
        run_length_encode(123)

def test_run_length_encode_none():
    with pytest.raises(TypeError):
        run_length_encode(None)

# Additional edge cases
def test_run_length_encode_large_string():
    assert run_length_encode("aaabbbccc") == [('a', 3), ('b', 3), ('c', 3)]

def test_run_length_encode_mixed_characters():
    assert run_length_encode("aAaAa") == [('a', 1), ('A', 1), ('a', 1), ('A', 1), ('a', 1)]

def test_run_length_encode_special_characters():
    assert run_length_encode("!!@@") == [('!', 2), ('@', 2)]

def test_run_length_encode_numbers():
    assert run_length_encode("112233") == [('1', 2), ('2', 2), ('3', 2)]

def test_run_length_encode_long_string():
    assert run_length_encode("a" * 1000) == [('a', 1000)]

# Run the tests
if __name__ == "__main__":
    pytest.main()
```

These tests cover:

- **Happy paths**: Normal cases where the function should work as expected.
- **Edge cases**: Empty strings, strings with spaces, and strings with no repeated characters.
- **Error cases**: Non-string inputs and `None` input.
- **Additional edge cases**: Large strings, mixed characters, special characters, and numbers.

To run these tests, ensure you have pytest installed and execute the tests using a test runner.
